using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x=0,f=1;char ch=gc();
		wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=gc();}
		wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
		return x*f;
	}
	void write(ll x)
	{
		if(x<0)pc('-'),x=-x;
		if(x>9)write(x/10);
		pc(x%10+'0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;
int A,B,C;
int b[300005];
int a[105][105][105];
void dfs(int x,int y,int z)
{
	if(x==0)b[z]=1;
	a[x][y][z]=1;
	if(x!=0)
	{
		if(x+y<=B)
		{
			if(a[0][x+y][z]==0)dfs(0,x+y,z);
		}
		else
		{
			if(a[x+y-B][B][z]==0)dfs(x+y-B,B,z);
		}
		if(x+z<=C)
		{
			if(a[0][y][z+x]==0)dfs(0,y,z+x);
		}
		else
		{
			if(a[x+z-C][y][C]==0)dfs(x+z-C,y,C);
		}
	}
	if(y!=0)
	{
		if(x+y<=A)
		{
			if(a[x+y][0][z]==0)dfs(x+y,0,z);
		}
		else
		{
			if(a[A][x+y-A][z]==0)dfs(A,x+y-A,z);
		}
		if(y+z<=C)
		{
			if(a[x][0][y+z]==0)dfs(x,0,y+z);
		}
		else
		{
			if(a[x][z+y-C][C]==0)dfs(x,z+y-C,C);
		}
	}
	if(z!=0)
	{
		if(x+z<=A)
		{
			if(a[x+z][0][y]==0)dfs(x+z,0,y);
		}
		else
		{
			if(a[A][y][x+z-A]==0)dfs(A,y,x+z-A);
		}
		if(y+z<=B)
		{
			if(a[x][y+z][0]==0)dfs(x,y+z,0);
		}
		else
		{
			if(a[x][B][y+z-B]==0)dfs(x,B,y+z-B);
		}
	}
}
signed main(void)
{
	A=read();
	B=read();
	C=read();
	dfs(0,0,C);
	FOR(i,0,C+A+B)
	{
		if(b[i]==1)write(i),pc(' ');
	}
	return false;
}
